import{_ as l,c as i,o as e,a}from"./app.4d65903c.js";const A=JSON.parse('{"title":"APP测试方向","description":"","frontmatter":{},"headers":[{"level":2,"title":"1）功能测试","slug":"_1-功能测试","link":"#_1-功能测试","children":[]},{"level":2,"title":"2）性能测试","slug":"_2-性能测试","link":"#_2-性能测试","children":[]},{"level":2,"title":"3）兼容性测试","slug":"_3-兼容性测试","link":"#_3-兼容性测试","children":[]},{"level":2,"title":"4）冲突测试","slug":"_4-冲突测试","link":"#_4-冲突测试","children":[]},{"level":2,"title":"5）异常情况测试","slug":"_5-异常情况测试","link":"#_5-异常情况测试","children":[]},{"level":2,"title":"6）其他测试点","slug":"_6-其他测试点","link":"#_6-其他测试点","children":[]}],"relativePath":"articles/04-面试/软件测试/APP测试.md"}'),d={name:"articles/04-面试/软件测试/APP测试.md"},r=a('<h1 id="app测试方向" tabindex="-1">APP测试方向 <a class="header-anchor" href="#app测试方向" aria-hidden="true">#</a></h1><h2 id="_1-功能测试" tabindex="-1">1）功能测试 <a class="header-anchor" href="#_1-功能测试" aria-hidden="true">#</a></h2><p>功能性测试目的是帮助我们验证该功能是否被实现以及该功能是否符合产品需求文档，主要包括：</p><ol><li>业务逻辑测试：主要验证App业务是否符合预期，一般测试流程为：<code>阅读需求文档→了解开发实现→画出开发实现流程图→编写测试用例</code></li><li>UI测试：由于手机的某些局限性，如手机的显示区域小，不能有太丰富的展示效果；手机的操作主要依赖于拇指，交互过程不能设计得太复杂等，所以需要关注界面元素的布局和自适应性 （横屏和竖屏）、界面的美观和简洁度以及用户体验。</li></ol><p>注：功能测试方法可以有手动测试和自动化测试。</p><h2 id="_2-性能测试" tabindex="-1">2）性能测试 <a class="header-anchor" href="#_2-性能测试" aria-hidden="true">#</a></h2><p>衡量一个APP做的好不好标准，除了功能还有性能。由于手机内存限制，很容易出现内存泄漏、越界问题，需要保证一款合格的App在高、中、低端手机上都可以流畅运行。针对性能，我们关注的参数有</p><ul><li>内存</li><li>CPU测试</li><li>流量测试</li><li>耗电量测试</li><li>稳定性测试</li><li>APP安装和启动耗时</li></ul><p>通常的评判方法是与业内竞品做对比。</p><h2 id="_3-兼容性测试" tabindex="-1">3）兼容性测试 <a class="header-anchor" href="#_3-兼容性测试" aria-hidden="true">#</a></h2><p>不同型号的手机支持的图片格式、声音格式、动画格式不一样，需要选择尽可能通用的格式，或 者针对不同的型号进行配置选择，所以需要注意：</p><ol><li>手机分辨率，如主流分辨率<code>1080*1920</code>、<code>720*1080</code>、<code>480*720</code>及非主流分辨率，尤其注意pad</li><li>手机系统版本，如<code>Android10</code>、<code>Android12</code>、<code>Android N</code>等；</li><li>不同手机厂商，如MIUI、魅族等，注意Google的Android原生系统；</li><li>不同屏幕尺寸，小（2～3英寸），普通（4英寸左右），大（5～7英寸），超大（7英寸以上）</li></ol><h2 id="_4-冲突测试" tabindex="-1">4）冲突测试 <a class="header-anchor" href="#_4-冲突测试" aria-hidden="true">#</a></h2><p>冲突测试，就是把软件在各种安全软件环境下进行使用，检查是否会有报病毒木马、威胁等任何对被测软件不利的情况，这里的冲突测试专指与安全软件的冲突</p><p>因为安全软件可能会让我们的软件出现很多问题，比如app运行出错、阻止App获取一些权限、阻止app读取已经从系统获取了的权限、弹出窗口认为程序有威胁并直接删除等。在以下情况下需要做冲突测试：</p><ol><li>有手机用户本地程序信息的操作</li><li>安装及使用时有通讯录、短信、通话记录、摄像头等权限的申请</li><li>频繁访问网络</li><li>新增插件</li><li>有更改开机启动项</li></ol><h2 id="_5-异常情况测试" tabindex="-1">5）异常情况测试 <a class="header-anchor" href="#_5-异常情况测试" aria-hidden="true">#</a></h2><ol><li>弱网环境：App在使用过程中会遇到弱网环境，如在地铁里，导致出现丢包。测试时需要注意</li></ol><ul><li>2G网络</li><li>3G网络</li><li>请求超时</li><li>响应超时</li><li>网络抖动场景模拟</li></ul><ol start="2"><li>手机应用在操作过程中断网、断电、重启</li><li>手机锁屏、解锁</li><li>手机其他应用对App的影响，如推送通知、来电、收发短信、文件下载、听音乐等</li></ol><h2 id="_6-其他测试点" tabindex="-1">6）其他测试点 <a class="header-anchor" href="#_6-其他测试点" aria-hidden="true">#</a></h2><ol><li>App安装（从渠道商下载安装、通过apk安装）</li><li>App卸载</li><li>App升级（注意跨版本升级）</li><li>覆盖安装（同版本覆盖、高版本覆盖低版本）</li></ol>',22),o=[r];function t(c,n,h,_,p,s){return e(),i("div",null,o)}const P=l(d,[["render",t]]);export{A as __pageData,P as default};
